 {"id":"bd-35p","title":"Implement Progress and Spinner widgets","description":"# Implement Progress and Spinner Widgets

## Background & Strategic Importance
Progress indicators and spinners are essential for agent harness UIs showing tool execution status. When an agent is running a tool (like `grep`, `cargo build`, or an API call), users need visual feedback that something is happening. These widgets provide that feedback.

## Why P2 (But Blocks Agent Harness)
While marked P2, these widgets are depended on by the Agent Harness reference application (bd-2kj). The harness needs:
- Spinner to show "tool running" state
- Progress bar for operations with known duration/steps

---

## Technical Design

### Spinner Widget

```rust
use tracing::{debug, trace, instrument};

/// Animated spinner for indeterminate progress.
///
/// # Design Rationale
/// - Static frame arrays for memory efficiency
/// - Stateful widget pattern for animation frame tracking
/// - Multiple presets for different aesthetic preferences
/// - Label support for context ("Loading..." text)
pub struct Spinner {
    /// Animation frames (static borrowed strings)
    frames: &'static [&'static str],
    /// Style for spinner character
    style: Style,
    /// Optional label shown after spinner
    label: Option<Text>,
    /// Speed in ticks per frame (default: 1)
    speed: u8,
}

/// Preset spinner animations.
pub mod spinners {
    /// Braille dot pattern (smooth, modern)
    pub const DOTS: &[&str] = &["⠋", "⠙", "⠹", "⠸", "⠼", "⠴", "⠦", "⠧", "⠇", "⠏"];
    /// Classic ASCII (works everywhere)
    pub const LINE: &[&str] = &["|", "/", "-", "\\"];
    /// Full braille rotation
    pub const BRAILLE: &[&str] = &["⣾", "⣽", "⣻", "⢿", "⡿", "⣟", "⣯", "⣷"];
    /// Moon phases (fun, distinctive)
    pub const MOON: &[&str] = &["🌑", "🌒", "🌓", "🌔", "🌕", "🌖", "🌗", "🌘"];
    /// Block animation
    pub const BLOCKS: &[&str] = &["▖", "▘", "▝", "▗"];
    /// Arrow rotation
    pub const ARROWS: &[&str] = &["←", "↖", "↑", "↗", "→", "↘", "↓", "↙"];
    /// Simple dots
    pub const SIMPLE_DOTS: &[&str] = &[".", "..", "...", ".."];
}

/// State for spinner animation.
pub struct SpinnerState {
    /// Current frame index
    frame: usize,
    /// Tick counter for speed control
    tick_count: u32,
}

impl SpinnerState {
    pub fn new() -> Self {
        Self { frame: 0, tick_count: 0 }
    }

    /// Advance to next frame. Call this from runtime tick handler.
    pub fn tick(&mut self, total_frames: usize, speed: u8) {
        self.tick_count += 1;
        if self.tick_count >= speed as u32 {
            self.tick_count = 0;
            self.frame = (self.frame + 1) % total_frames;
            trace!(frame = self.frame, "Spinner tick");
        }
    }
}
```

### Spinner API

```rust
impl Spinner {
    /// Create spinner with dots preset.
    pub fn new() -> Self {
        debug!("Creating Spinner with dots preset");
        Self {
            frames: spinners::DOTS,
            style: Style::default().fg(Color::Cyan),
            label: None,
            speed: 1,
        }
    }

    /// Use a different preset.
    pub fn preset(mut self, frames: &'static [&'static str]) -> Self {
        self.frames = frames;
        self
    }

    /// Add label text.
    pub fn label(mut self, label: impl Into<Text>) -> Self {
        self.label = Some(label.into());
        self
    }

    /// Set style for spinner character.
    pub fn style(mut self, style: Style) -> Self {
        self.style = style;
        self
    }

    /// Set animation speed (ticks per frame, higher = slower).
    pub fn speed(mut self, speed: u8) -> Self {
        self.speed = speed.max(1);
        self
    }
}

impl StatefulWidget for Spinner {
    type State = SpinnerState;

    fn render(&self, area: Rect, buf: &mut Buffer, state: &mut Self::State) {
        if area.width == 0 || area.height == 0 {
            return;
        }

        // Render spinner frame
        let frame = self.frames[state.frame % self.frames.len()];
        let spinner_width = unicode_width::UnicodeWidthStr::width(frame) as u16;
        buf.set_string(area.x, area.y, frame, self.style);

        // Render label if present
        if let Some(ref label) = self.label {
            let label_x = area.x + spinner_width + 1;
            if label_x < area.x + area.width {
                let label_area = Rect::new(label_x, area.y, area.width - spinner_width - 1, 1);
                label.render(label_area, buf);
            }
        }
    }
}
```

### Progress Bar Widget

```rust
/// Progress bar for determinate progress (known total).
///
/// # Design Rationale
/// - f64 ratio for smooth progress (0.0 to 1.0)
/// - Configurable fill characters for aesthetic options
/// - Label position options (left, right, center, none)
/// - ETA calculation as optional companion
pub struct ProgressBar {
    /// Progress ratio (0.0 to 1.0)
    ratio: f64,
    /// Bar style
    bar_style: ProgressStyle,
    /// Optional label (e.g., "50%" or "5/10")
    label: Option<String>,
    /// Label position
    label_position: LabelPosition,
}

#[derive(Clone, Copy, Debug, Default)]
pub enum LabelPosition {
    /// Label on left of bar
    Left,
    /// Label on right of bar
    Right,
    /// Label centered over bar
    #[default]
    Center,
    /// No label
    Hidden,
}

/// Visual style for progress bar.
pub struct ProgressStyle {
    /// Style for filled portion
    fill_style: Style,
    /// Style for empty portion
    empty_style: Style,
    /// Style for partial fill (edge)
    partial_style: Style,
    /// Characters: [filled, partial, empty]
    chars: ProgressChars,
}

pub type ProgressChars = [char; 3];

/// Preset progress bar styles.
pub mod progress_styles {
    use super::ProgressChars;
    /// Block style (Unicode full/half/empty blocks)
    pub const BLOCK: ProgressChars = ['█', '▓', '░'];
    /// ASCII style (works everywhere)
    pub const ASCII: ProgressChars = ['=', '>', ' '];
    /// Dot style
    pub const DOTS: ProgressChars = ['●', '○', '○'];
    /// Fine blocks (8 levels)
    pub const FINE: ProgressChars = ['█', '▌', ' '];
}
```

### Progress Bar API

```rust
impl ProgressBar {
    /// Create progress bar at 0%.
    pub fn new() -> Self {
        debug!("Creating ProgressBar");
        Self {
            ratio: 0.0,
            bar_style: ProgressStyle::default(),
            label: None,
            label_position: LabelPosition::Center,
        }
    }

    /// Set progress ratio (clamped to 0.0..=1.0).
    pub fn ratio(mut self, ratio: f64) -> Self {
        self.ratio = ratio.clamp(0.0, 1.0);
        self
    }

    /// Set progress from current/total.
    pub fn progress(mut self, current: u64, total: u64) -> Self {
        self.ratio = if total == 0 { 0.0 } else { current as f64 / total as f64 };
        self
    }

    /// Auto-generate percentage label.
    pub fn with_percentage_label(mut self) -> Self {
        self.label = Some(format!("{:.0}%", self.ratio * 100.0));
        self
    }

    /// Auto-generate count label.
    pub fn with_count_label(mut self, current: u64, total: u64) -> Self {
        self.label = Some(format!("{}/{}", current, total));
        self
    }

    /// Set custom label.
    pub fn label(mut self, label: impl Into<String>) -> Self {
        self.label = Some(label.into());
        self
    }

    /// Set label position.
    pub fn label_position(mut self, position: LabelPosition) -> Self {
        self.label_position = position;
        self
    }

    /// Use a preset style.
    pub fn style(mut self, style: ProgressStyle) -> Self {
        self.bar_style = style;
        self
    }
}

impl Widget for ProgressBar {
    #[instrument(skip(self, area, buf), fields(ratio = self.ratio))]
    fn render(self, area: Rect, buf: &mut Buffer) {
        if area.width == 0 || area.height == 0 {
            return;
        }

        let width = area.width as usize;
        let filled_width = (self.ratio * width as f64) as usize;
        let partial = (self.ratio * width as f64).fract();

        // Build bar string
        let mut bar = String::with_capacity(width * 4); // Unicode can be multi-byte

        // Filled portion
        for _ in 0..filled_width.min(width) {
            bar.push(self.bar_style.chars[0]);
        }

        // Partial fill (if at edge)
        if filled_width < width && partial > 0.0 {
            bar.push(self.bar_style.chars[1]);
        }

        // Empty portion
        let remaining = width.saturating_sub(filled_width).saturating_sub(if partial > 0.0 { 1 } else { 0 });
        for _ in 0..remaining {
            bar.push(self.bar_style.chars[2]);
        }

        // Render bar
        let bar_graphemes: Vec<&str> = bar.graphemes(true).take(width).collect();
        for (i, g) in bar_graphemes.iter().enumerate() {
            let style = if i < filled_width {
                self.bar_style.fill_style
            } else if i == filled_width && partial > 0.0 {
                self.bar_style.partial_style
            } else {
                self.bar_style.empty_style
            };
            buf.set_string(area.x + i as u16, area.y, g, style);
        }

        // Render label
        if let Some(ref label) = self.label {
            let label_x = match self.label_position {
                LabelPosition::Left => area.x,
                LabelPosition::Right => area.x + area.width - label.len() as u16,
                LabelPosition::Center => area.x + (area.width - label.len() as u16) / 2,
                LabelPosition::Hidden => return,
            };
            buf.set_string(label_x, area.y, label, Style::default().add_modifier(Modifier::BOLD));
        }

        trace!(filled_width, "Rendered ProgressBar");
    }
}
